code = """import json
import re

# Read the full result from the file
file_path = locals()['var_functions.query_db:12']
with open(file_path, 'r') as f:
    articles = json.load(f)

# Define precise sports keywords (excluding general terms like "game")
sports_keywords = [
    'football', 'basketball', 'baseball', 'soccer', 'tennis', 'golf', 'hockey',
    'cricket', 'rugby', 'volleyball', 'badminton', 'squash', 'athlete',
    'olympic', 'olympics', 'championship', 'tournament', 'nba', 'nfl',
    'mlb', 'nhl', 'world cup', 'super bowl', 'world series', 'marathon',
    'boxing', 'wrestling', 'swimming', 'cycling', 'skiing', 'skating',
    'sailing', 'fencing', 'judo', 'karate', 'mma', 'ufc', 'fifa', 'ncaa',
    'ryder cup', 'pga', 'coach', 'quarterback', 'pitcher', 'goalkeeper',
    'point guard', 'forward', 'defender', 'midfielder', 'striker',
    'batter', 'home run', 'touchdown', 'goal', 'medal', 'medalist'
]

# False positive indicators (tech/computer context)
tech_indicators = [
    'windows', 'microsoft', 'intel', 'amd', 'linux', 'unix', 'software',
    'program', 'application', 'browser', 'ie', 'google', 'developer',
    'developers', 'memory', 'processor', 'chip', 'hard drive', 'simcity'
]

sports_articles = []

for article in articles:
    title_lower = article['title'].lower()
    desc_lower = article['description'].lower()
    
    # Check for tech indicators first
    is_tech = False
    for indicator in tech_indicators:
        if indicator in title_lower or indicator in desc_lower:
            is_tech = True
            break
    
    # Only check for sports if not tech
    if not is_tech:
        is_sports = False
        for keyword in sports_keywords:
            if keyword in title_lower or keyword in desc_lower:
                is_sports = True
                break
        
        if is_sports:
            sports_articles.append({
                'article_id': article['article_id'],
                'title': article['title'],
                'description': article['description'],
                'description_length': len(article['description'])
            })

# Find the sports article with the longest description
if sports_articles:
    longest_article = max(sports_articles, key=lambda x: x['description_length'])
    result = [longest_article['title'], longest_article['description_length']]
else:
    result = ['No sports articles found', 0]

print('__RESULT__:')
print(json.dumps(result))"""

